// Step 1: Ingestion — normalize and validate incoming message
const body = $input.first().json.body || $input.first().json;

const message = {
  id: `msg_${Date.now()}`,
  source: (body.source || 'Unknown').trim(),
  timestamp: new Date().toISOString(),
  raw_message: (body.raw_message || body.message || body.content || '').trim()
};

if (!message.raw_message) {
  throw new Error('Missing required field: raw_message');
}

return [{ json: message }];

