// Parse classification — JSON is guaranteed by response_format: json_object
const response = $input.first().json;
const content = response.choices[0].message.content.trim();

let classification;
try {
  classification = JSON.parse(content);
} catch (e) {
  throw new Error(`Classification parse failed: ${content.substring(0, 200)}`);
}

// Normalise and validate
const VALID_CATEGORIES = ['Bug Report', 'Feature Request', 'Billing Issue', 'Technical Question', 'Incident / Outage'];
const VALID_PRIORITIES = ['Low', 'Medium', 'High'];

classification.category = (classification.category || '').trim();
classification.priority  = (classification.priority  || '').trim();
classification.confidence_score = parseFloat(classification.confidence_score) || 0;

if (!VALID_CATEGORIES.includes(classification.category)) {
  throw new Error(`Invalid category '${classification.category}'. Expected one of: ${VALID_CATEGORIES.join(', ')}`);
}
if (!VALID_PRIORITIES.includes(classification.priority)) {
  throw new Error(`Invalid priority '${classification.priority}'. Expected: Low, Medium, High`);
}
if (classification.confidence_score < 0 || classification.confidence_score > 1) {
  throw new Error(`confidence_score must be 0.0-1.0, got: ${classification.confidence_score}`);
}

const prev = $('Step 1: Ingestion').first().json;
return [{ json: { ...prev, classification } }];

