// Parse enrichment + apply routing + escalation logic
const response = $input.first().json;
const content = response.choices[0].message.content.trim();

let enrichment;
try {
  enrichment = JSON.parse(content);
} catch (e) {
  throw new Error(`Enrichment parse failed: ${content.substring(0, 200)}`);
}

// Ensure identifiers is always an object
if (!enrichment.identifiers || typeof enrichment.identifiers !== 'object') {
  enrichment.identifiers = {};
}

const prev = $('Parse Classification').first().json;
const { classification, raw_message } = prev;

// ── Routing table ───────────────────────────────────────────────────────────
const ROUTING = {
  'Bug Report':         'Engineering',
  'Incident / Outage':  'Engineering',
  'Feature Request':    'Product',
  'Technical Question': 'IT / Security',
  'Billing Issue':      'Billing'
};

// ── Escalation logic ────────────────────────────────────────────────────────
const ESCALATION_KEYWORDS = [
  'outage',
  'down for all users',
  'multiple users affected',
  'stopped loading',
  'completely down'
];
const CONFIDENCE_THRESHOLD = 0.70;
const BILLING_THRESHOLD    = 200;

let escalationFlag   = false;
let escalationReason = null;
const msgLower = raw_message.toLowerCase();

// Rule 1: low confidence
if (classification.confidence_score < CONFIDENCE_THRESHOLD) {
  escalationFlag   = true;
  escalationReason = `Low confidence (${Math.round(classification.confidence_score * 100)}%) — below ${CONFIDENCE_THRESHOLD * 100}% threshold`;
}

// Rule 2: escalation keywords
if (!escalationFlag) {
  for (const kw of ESCALATION_KEYWORDS) {
    if (msgLower.includes(kw)) {
      escalationFlag   = true;
      escalationReason = `Escalation keyword matched: "${kw}"`;
      break;
    }
  }
}

// Rule 3: billing discrepancy > $200
if (!escalationFlag && enrichment.identifiers.discrepancy) {
  const disc = parseFloat(String(enrichment.identifiers.discrepancy).replace(/[$,]/g, ''));
  if (!isNaN(disc) && disc > BILLING_THRESHOLD) {
    escalationFlag   = true;
    escalationReason = `Billing discrepancy $${disc} exceeds $${BILLING_THRESHOLD} threshold`;
  }
}

// Rule 4: Incident/Outage category always escalates
if (!escalationFlag && classification.category === 'Incident / Outage') {
  escalationFlag   = true;
  escalationReason = 'Incident/Outage auto-escalates regardless of confidence';
}

const standardQueue    = ROUTING[classification.category] || 'Escalation';
const destinationQueue = escalationFlag ? 'Escalation' : standardQueue;

const routing = {
  destination_queue: destinationQueue,
  routing_reason:    escalationFlag
    ? escalationReason
    : `${classification.category} routes to ${destinationQueue}`,
  escalation_flag:   escalationFlag,
  escalation_reason: escalationReason
};

return [{ json: { ...prev, enrichment, routing } }];

