const prev = $('Steps 4+6: Routing & Escalation').first().json;

const finalRecord = {
  // ── Identity ────────────────────────────────────────
  id:          prev.id,
  source:      prev.source,
  timestamp:   prev.timestamp,
  raw_message: prev.raw_message,

  // ── Step 2: Classification ──────────────────────────
  category:         prev.classification.category,
  priority:         prev.classification.priority,
  confidence_score: prev.classification.confidence_score,

  // ── Step 3: Enrichment ──────────────────────────────
  core_issue:    prev.enrichment.core_issue,
  identifiers:   prev.enrichment.identifiers,
  urgency_signal: prev.enrichment.urgency_signal,

